"use client";

import { AnimatePresence, motion } from "framer-motion";
import { ChevronRight } from "lucide-react";
import { cn } from "@/lib/utils";

export interface BreadcrumbItem {
  label: string;
  href?: string;
  icon?: React.ReactNode;
}

export interface AnimatedBreadcrumbsProps {
  items: BreadcrumbItem[];
  className?: string;
}

const separatorVariants = {
  initial: { opacity: 0, scale: 0, rotate: -90 },
  animate: { opacity: 1, scale: 1, rotate: 0 },
  exit: { opacity: 0, scale: 0, rotate: 90 },
};
const itemVariants = {
  initial: { opacity: 0, x: -12, scale: 0.85 },
  animate: { opacity: 1, x: 0, scale: 1 },
  exit: { opacity: 0, x: 12, scale: 0.85 },
};
export function AnimatedBreadcrumbs({ items, className }: AnimatedBreadcrumbsProps) {
  return (
    <nav aria-label="breadcrumb" className={cn("inline-flex", className)}>
      <ol className="flex items-center gap-1">
        <AnimatePresence mode="popLayout">
          {items.map((item, index) => {
            const isLast = index === items.length - 1;
            return (
              <motion.li
                key={item.label}
                className="flex items-center gap-1"
                layout
                initial="initial"
                animate="animate"
                exit="exit"
                variants={itemVariants}
                transition={{
                  type: "spring",
                  stiffness: 500,
                  damping: 30,
                  delay: index * 0.06,
                }}
              >
                {index > 0 && (
                  <motion.span
                    variants={separatorVariants}
                    transition={{ type: "spring", stiffness: 500, damping: 25 }}
                    className="text-muted-foreground mx-0.5"
                  >
                    <ChevronRight className="h-3.5 w-3.5" />
                  </motion.span>
                )}
                <motion.a
                  href={item.href || "#"}
                  className={cn(
                    "relative inline-flex items-center gap-1.5 rounded-md px-2.5 py-1.5 text-sm font-medium transition-colors",
                    isLast
                      ? "text-foreground cursor-default"
                      : "text-muted-foreground hover:text-foreground"
                  )}
                  whileHover={
                    !isLast
                      ? { scale: 1.06, y: -1 }
                      : undefined
                  }
                  whileTap={!isLast ? { scale: 0.96 } : undefined}
                  transition={{ type: "spring", stiffness: 400, damping: 17 }}
                >
                  {/* Hover background glow */}
                  {!isLast && (
                    <motion.span
                      className="absolute inset-0 rounded-md bg-accent"
                      initial={{ opacity: 0 }}
                      whileHover={{ opacity: 1 }}
                      transition={{ duration: 0.2 }}
                      style={{ zIndex: -1 }}
                    />
                  )}
                  {/* Shimmer on active item */}
                  {isLast && (
                    <motion.span
                      className="absolute inset-0 rounded-md overflow-hidden"
                      style={{ zIndex: -1 }}
                    >
                      <motion.span
                        className="absolute inset-0 bg-linear-to-r from-transparent via-accent to-transparent"
                        animate={{ x: ["-100%", "200%"] }}
                        transition={{
                          duration: 2.5,
                          repeat: Infinity,
                          repeatDelay: 3,
                          ease: "easeInOut",
                        }}
                      />
                    </motion.span>
                  )}
                  {item.icon && (
                    <motion.span
                      initial={{ rotate: -20, opacity: 0 }}
                      animate={{ rotate: 0, opacity: 1 }}
                      transition={{ type: "spring", stiffness: 300, damping: 20, delay: index * 0.06 + 0.1 }}
                    >
                      {item.icon}
                    </motion.span>
                  )}
                  <span>{item.label}</span>
                  {/* Active dot indicator */}
                  {isLast && (
                    <motion.span
                      className="ml-0.5 h-1.5 w-1.5 rounded-full bg-primary"
                      initial={{ scale: 0 }}
                      animate={{ scale: [1, 1.4, 1] }}
                      transition={{
                        scale: {
                          duration: 2,
                          repeat: Infinity,
                          ease: "easeInOut",
                        },
                        delay: 0.3,
                      }}
                    />
                  )}
                </motion.a>
              </motion.li>
            );
          })}
        </AnimatePresence>
      </ol>
    </nav>
  );
}
